using AiVideoStudio.Domain.Entities;using AiVideoStudio.Domain.Enums;using AiVideoStudio.Domain.Interfaces;using AiVideoStudio.Shared.Responses;using MongoDB.Driver;
namespace AiVideoStudio.Infrastructure.Mongo.Repositories;
public sealed class NotificationRepository:INotificationRepository{private readonly IMongoCollection<SystemNotification> _c;public NotificationRepository(MongoDbContext c):this(c.Notifications){}public NotificationRepository(IMongoCollection<SystemNotification> c)=>_c=c;public Task<SystemNotification?> GetAsync(string id,CancellationToken ct=default)=>_c.Find(x=>x.Id==id).FirstOrDefaultAsync(ct)!;public Task AddAsync(SystemNotification x,CancellationToken ct=default)=>_c.InsertOneAsync(x,cancellationToken:ct);public async Task UpdateAsync(SystemNotification x,CancellationToken ct=default)=>await _c.ReplaceOneAsync(i=>i.Id==x.Id,x,cancellationToken:ct);public async Task<PagedResult<SystemNotification>> GetByUserAsync(string user,int page,int size,CancellationToken ct=default){var f=Builders<SystemNotification>.Filter.Eq(x=>x.UserId,user);var total=await _c.CountDocumentsAsync(f,cancellationToken:ct);var items=await _c.Find(f).SortByDescending(x=>x.CreatedAt).Skip((page-1)*size).Limit(size).ToListAsync(ct);return new(items,(int)total,page,size);}}
public sealed class QuotaRepository:IQuotaRepository{private readonly IMongoCollection<UserQuota> _q;private readonly IMongoCollection<UsageRecord> _u;public QuotaRepository(MongoDbContext c):this(c.UserQuotas,c.UsageRecords){}public QuotaRepository(IMongoCollection<UserQuota> q,IMongoCollection<UsageRecord> u){_q=q;_u=u;}public Task<UserQuota?> GetAsync(string user,QuotaType type,CancellationToken ct=default)=>_q.Find(x=>x.UserId==user&&x.Type==type).FirstOrDefaultAsync(ct)!;public async Task UpsertAsync(UserQuota x,CancellationToken ct=default)=>await _q.ReplaceOneAsync(i=>i.UserId==x.UserId&&i.Type==x.Type,x,new ReplaceOptions{IsUpsert=true},ct);public Task AddUsageAsync(UsageRecord x,CancellationToken ct=default)=>_u.InsertOneAsync(x,cancellationToken:ct);}
public sealed class SystemConfigurationRepository:ISystemConfigurationRepository{private readonly IMongoCollection<SystemConfiguration> _c;public SystemConfigurationRepository(MongoDbContext c):this(c.SystemConfigurations){}public SystemConfigurationRepository(IMongoCollection<SystemConfiguration> c)=>_c=c;public async Task<IReadOnlyList<SystemConfiguration>> GetAllAsync(CancellationToken ct=default)=>await _c.Find(FilterDefinition<SystemConfiguration>.Empty).SortBy(x=>x.Key).ToListAsync(ct);public Task<SystemConfiguration?> GetAsync(string key,CancellationToken ct=default)=>_c.Find(x=>x.Key==key).FirstOrDefaultAsync(ct)!;public async Task UpsertAsync(SystemConfiguration x,CancellationToken ct=default)=>await _c.ReplaceOneAsync(i=>i.Key==x.Key,x,new ReplaceOptions{IsUpsert=true},ct);}
public sealed class MaintenanceRepository:IMaintenanceRepository{private readonly IMongoCollection<MaintenanceTask> _c;public MaintenanceRepository(MongoDbContext c):this(c.MaintenanceTasks){}public MaintenanceRepository(IMongoCollection<MaintenanceTask> c)=>_c=c;public Task AddAsync(MaintenanceTask x,CancellationToken ct=default)=>_c.InsertOneAsync(x,cancellationToken:ct);public async Task UpdateAsync(MaintenanceTask x,CancellationToken ct=default)=>await _c.ReplaceOneAsync(i=>i.Id==x.Id,x,cancellationToken:ct);public Task<MaintenanceTask?> GetAsync(string id,CancellationToken ct=default)=>_c.Find(x=>x.Id==id).FirstOrDefaultAsync(ct)!;}
